const jwt = require('jsonwebtoken');

const userSchema = new mongoose.Schema({
  username: String,
  email: String,
  password: String,
  tokens: [{ type: String, expires: Date }]
});

userSchema.methods.generateToken = function() {
  const token = jwt.sign({ _id: this._id }, process.env.SECRET_KEY, { expiresIn: '1h' });
  this.tokens.push({ token, expires: new Date(Date.now() + 3600000) });
  return token;
};

userSchema.methods.revokeToken = function(token) {
  this.tokens = this.tokens.filter(t => t.token !== token);
};

const User = mongoose.model('User', userSchema);

module.exports = User;
